sql:
SELECT age_group_id, age_range
FROM age_groups
WHERE age_group_id > 5;

SELECT rate_id
FROM rates
WHERE preferred_rate > (SELECT AVG(preferred_rate) FROM rates);

SELECT AVG(preferred_rate) as average_preferred_rate
FROM rates
WHERE rate_table_id = 1;

SELECT location_id 
FROM location_rates 
WHERE rate_table_id = 1;

SELECT COUNT(*)
FROM age_groups
WHERE CAST(SUBSTR(age_range, 1, INSTR(age_range, '-') - 1) AS INTEGER) > 20;

SELECT u.user_name, u.role, rh.rate_history_id, rh.effective_date 
FROM users u 
JOIN rate_history rh ON u.user_id = rh.created_by;

external_knowledge:
- Certain value refers to 20;
- Specific rate category corresponds to rate table ID 1;
- Favored rate is synonymous with preferred rate.

sql:
SELECT DISTINCT age_group_id
FROM rates
WHERE rate_table_id = 1 AND preferred_rate > 20;

SELECT DISTINCT gl.location_name
FROM geographic_locations gl
JOIN location_rates lr ON gl.location_id = lr.location_id;

external_knowledge:
- "resemble the title of an ocean liner" refers to rate table names starting with "Table%";
- "anchored in the harbor of the USA" means the location is USA;
- "sails raised before the beginning of the year 2022" refers to effective dates before 2022-01-01;
- "seasoned navigator (actuary)" and "skilled captain (underwriter)" refer to user roles 'actuary' and 'underwriter'.

sql:
SELECT rt.rate_table_id, rt.rate_table_name, rt.description, rt.created_at, gl.location_id, gl.location_name
FROM rate_tables rt
JOIN geographic_locations gl ON rt.location_id = gl.location_id;

SELECT rate_analytics_id
FROM rate_analytics
WHERE analysis_type = 'comparison' AND created_by = 0;

external_knowledge:
- 'Actuaries' are professionals who use mathematical skills to define, manage, and quantify the financial impact of risk and uncertainty; 
- 'Latest rate updates' refer to the most recent entries in the `rates` table based on the `updated_at` timestamp;
- 'Table 2' and 'USA' are specific identifiers for rate tables and locations, respectively.

sql:
SELECT rate_table_id, description
FROM rate_tables
WHERE rate_table_name = 'Table 2';

SELECT ag.age_range, r.preferred_rate
FROM rates r
JOIN age_groups ag ON r.age_group_id = ag.age_group_id
WHERE r.preferred_rate = (
    SELECT MAX(preferred_rate) FROM rates
);

SELECT rates.rate_id, rate_tables.rate_table_name
FROM rates
INNER JOIN rate_tables ON rates.rate_table_id = rate_tables.rate_table_id;

SELECT rate_table_name 
FROM rate_tables 
WHERE rate_table_id = 1;

SELECT plan_type_name
   FROM plan_types
   WHERE plan_type_id = 2;
